const data   = $input.first().json;
const issues = data.issues || [];

const tasks = issues.map(issue => {
  const f = issue.fields || {};
  return {
    key:      issue.key,
    summary:  (f.summary || '').substring(0, 120),
    type:     f.issuetype?.name  || 'Task',
    status:   f.status?.name     || 'To Do',
    priority: f.priority?.name   || 'Medium',
    assignee: f.assignee?.displayName || 'Sin asignar',
    reporter: f.reporter?.displayName || '',
    created:  (f.created || '').substring(0, 10),
    url:      'https://qaprocess1.atlassian.net/browse/' + issue.key,
    description: (() => {
      const d = f.description;
      if (!d) return '';
      if (typeof d === 'string') return d.substring(0, 200);
      try {
        return (d.content||[]).flatMap(b=>(b.content||[]).map(c=>c.text||'')).join(' ').substring(0,200);
      } catch { return ''; }
    })(),
  };
});

const fecha = new Date().toLocaleString('es-CL', { timeZone: 'America/Santiago' });
const today = new Date().toISOString().split('T')[0];

return [{ json: { tasks, total: tasks.length, fecha, date: today } }];

const item  = $input.first().json;
const tasks = item.tasks || [];
const fecha = item.fecha || '';

const lines = tasks.map(t =>
  `📋 *${t.key}* — ${t.summary}\n` +
  `   Prioridad: ${t.priority} | Asignado: ${t.assignee}\n` +
  `   ${t.url}`
).join('\n\n');

const msg =
  `🆕 *Nueva Task QA — KAN*\n` +
  `Fecha: ${fecha}\n` +
  `Total: ${tasks.length} task(s)\n\n` +
  lines;

return [{ json: { ...item, mensajeWhatsApp: encodeURIComponent(msg) } }];

const now = Date.now();
const MAX_AGE_MS = 150000; // 2.5 minutos

const allIssues = $input.first().json.issues || [];

const nuevos = allIssues.filter(issue => {
  // Filtro 1: timestamp - issue debe tener menos de 2.5 min de vida
  const created = issue.fields && issue.fields.created;
  if (!created) return false;
  const age = now - new Date(created).getTime();
  if (age > MAX_AGE_MS) return false;

  // Filtro 2: status no debe ser Done
  const statusName = issue.fields && issue.fields.status && issue.fields.status.name;
  if (!statusName || statusName === 'Done' || statusName === 'done') return false;

  return true;
});

// Siempre retornar objeto explicito — nunca [] vacio
// para que el IF node reciba datos y evalúe correctamente
return [{ json: { total: nuevos.length, issues: nuevos } }];
